import{_ as t,c as o,o as a,ag as r}from"./chunks/framework.Bw-5EFTY.js";const m=JSON.parse('{"title":"Team Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/agent-team/docs/SPEC.md","filePath":"packages/agent-team/docs/SPEC.md"}'),d={name:"packages/agent-team/docs/SPEC.md"};function s(i,e,n,c,l,p){return a(),o("div",null,e[0]||(e[0]=[r(`<h1 id="team-specification" tabindex="-1">Team Specification <a class="header-anchor" href="#team-specification" aria-label="Permalink to &quot;Team Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><ul><li>Owns multi-agent teamwork behavior for Robota, including template-based task assignment, agent coordination, and delegation-oriented orchestration.</li><li>Provides a set of tools (FunctionTool and RelayMcpTool) that allow a parent agent to dynamically spawn and delegate work to child agent instances using predefined templates.</li><li>Manages a built-in template registry that defines agent configurations (provider, model, temperature, system message) for common task archetypes.</li></ul><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Does not redefine core agent contracts. <code>Robota</code>, tool interfaces (<code>IToolSchema</code>, <code>IToolResult</code>, <code>TToolParameters</code>), and event interfaces (<code>IEventService</code>, <code>IAIProvider</code>) are imported from <code>@robota-sdk/agent-core</code>. <code>FunctionTool</code> is imported from <code>@robota-sdk/agent-tools</code>. <code>RelayMcpTool</code> is imported from <code>@robota-sdk/agent-tool-mcp</code>. <code>bindWithOwnerPath</code> is imported from <code>@robota-sdk/agent-event-service</code>.</li><li>Keeps team coordination policies explicit and separate from provider integration.</li><li>Does not own AI provider implementations; provider and model selection is resolved through <code>@robota-sdk/agent-core</code> infrastructure.</li><li>Does not manage session persistence or conversation history; those concerns belong to <code>@robota-sdk/agent-sessions</code>.</li><li>Template definitions are static JSON; no runtime template creation or persistence API is exposed.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The package follows a single-layer structure with one functional module:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/</span></span>
<span class="line"><span>  index.ts                          # Public barrel export</span></span>
<span class="line"><span>  assign-task/</span></span>
<span class="line"><span>    relay-assign-task.ts            # Tool definitions and relay logic</span></span>
<span class="line"><span>    templates.json                  # Built-in template registry</span></span></code></pre></div><p><strong>Design patterns used:</strong></p><ul><li><strong>Tool-as-capability pattern</strong>: Each team operation is exposed as a tool instance (<code>FunctionTool</code> or <code>RelayMcpTool</code>) that agents can invoke, following the Robota tool protocol.</li><li><strong>Relay delegation</strong>: <code>createAssignTaskRelayTool</code> creates a <code>RelayMcpTool</code> that spawns a new <code>Robota</code> agent instance with template-derived configuration, executes a prompt, and returns the result. The relay tool receives an <code>IEventService</code> for owner-path-aware event propagation.</li><li><strong>Owner path propagation</strong>: When delegating, the relay tool extends the caller&#39;s <code>ownerPath</code> with a new agent segment, ensuring traceability through the event system.</li><li><strong>Template registry</strong>: Agent configurations are defined declaratively in <code>templates.json</code> and looked up by ID at execution time.</li></ul><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package defines a minimal set of local types. Most types are imported from <code>@robota-sdk/agent-core</code>.</p><table tabindex="0"><thead><tr><th>Type</th><th>Kind</th><th>Owner</th><th>Description</th></tr></thead><tbody><tr><td><code>ITemplateEntry</code></td><td>interface (local)</td><td><code>@robota-sdk/agent-team</code></td><td>Shape of a template record: id, name, description, provider, model, temperature, systemMessage</td></tr></tbody></table><p>All other types used in the public API (<code>IToolSchema</code>, <code>IToolResult</code>, <code>TToolParameters</code>, <code>IEventService</code>, <code>IAIProvider</code>, <code>IAgentConfig</code>, <code>IOwnerPathSegment</code>, <code>Robota</code>) are owned by <code>@robota-sdk/agent-core</code>. <code>FunctionTool</code> is owned by <code>@robota-sdk/agent-tools</code>. <code>RelayMcpTool</code> is owned by <code>@robota-sdk/agent-tool-mcp</code>.</p><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>listTemplateCategoriesTool</code></td><td><code>FunctionTool</code> instance</td><td>Returns the list of template categories. Currently returns a single &quot;Default Templates&quot; category.</td></tr><tr><td><code>listTemplatesTool</code></td><td><code>FunctionTool</code> instance</td><td>Returns available templates, optionally filtered by category. Returns id, name, description, and categoryId for each template.</td></tr><tr><td><code>getTemplateDetailTool</code></td><td><code>FunctionTool</code> instance</td><td>Returns full details of a specific template by <code>templateId</code>. Throws if the template is not found.</td></tr><tr><td><code>createAssignTaskRelayTool</code></td><td>factory function</td><td><code>(eventService: IEventService, aiProviders: IAIProvider[]) =&gt; RelayMcpTool</code>. Creates a relay tool that spawns a <code>Robota</code> agent from a template and runs a job description prompt. Required params: <code>templateId</code>, <code>jobDescription</code>. Optional overrides: <code>provider</code>, <code>model</code>, <code>temperature</code>, <code>maxTokens</code>, <code>context</code>.</td></tr></tbody></table><h3 id="tool-schemas" tabindex="-1">Tool Schemas <a class="header-anchor" href="#tool-schemas" aria-label="Permalink to &quot;Tool Schemas&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tool Name</th><th>Required Parameters</th><th>Optional Parameters</th></tr></thead><tbody><tr><td><code>listTemplateCategories</code></td><td>(none)</td><td>(none)</td></tr><tr><td><code>listTemplates</code></td><td>(none)</td><td><code>categoryId: string</code></td></tr><tr><td><code>getTemplateDetail</code></td><td><code>templateId: string</code></td><td>(none)</td></tr><tr><td><code>assignTask</code></td><td><code>templateId: string</code>, <code>jobDescription: string</code></td><td><code>provider: string</code>, <code>model: string</code>, <code>temperature: number</code>, <code>maxTokens: number</code>, <code>context: string</code></td></tr></tbody></table><h3 id="built-in-templates" tabindex="-1">Built-in Templates <a class="header-anchor" href="#built-in-templates" aria-label="Permalink to &quot;Built-in Templates&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Template ID</th><th>Name</th><th>Provider</th><th>Model</th></tr></thead><tbody><tr><td><code>general</code></td><td>General Purpose</td><td>openai</td><td>gpt-4o-mini</td></tr><tr><td><code>task_coordinator</code></td><td>Task Coordinator</td><td>openai</td><td>gpt-4o-mini</td></tr></tbody></table><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li><strong>Custom templates</strong>: Consumers cannot currently add templates at runtime. The template list is loaded from a static JSON file compiled into the package. To extend, the JSON file must be modified at the source level.</li><li><strong>Relay tool creation</strong>: <code>createAssignTaskRelayTool</code> accepts an <code>IEventService</code>, allowing consumers to wire the relay tool into any event infrastructure that implements the interface.</li><li><strong>Parameter overrides</strong>: The <code>assignTask</code> tool accepts optional <code>provider</code>, <code>model</code>, <code>temperature</code>, and <code>maxTokens</code> overrides, allowing callers to customize agent behavior per invocation without modifying templates.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>This package does not define a custom error hierarchy. It relies on:</p><ul><li>Standard JavaScript <code>Error</code> throws for missing required parameters and missing templates (in <code>getTemplateDetailTool</code> and the relay tool).</li><li><code>IToolResult</code> with <code>{ success: false, error: string }</code> for relay tool validation failures (missing <code>templateId</code>, missing <code>jobDescription</code>, template not found).</li><li>Context validation errors thrown with <code>[ASSIGN-TASK]</code> prefix when the relay execution context is missing required fields (<code>eventService</code>, <code>baseEventService</code>, <code>agentId</code>).</li></ul><p>All underlying agent execution errors propagate from <code>@robota-sdk/agent-core</code>.</p><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><p>None. This package defines no classes. All exports are tool instances created via factory functions. <code>FunctionTool</code> is from <code>@robota-sdk/agent-tools</code>; <code>RelayMcpTool</code> is from <code>@robota-sdk/agent-tool-mcp</code>.</p><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Consumer</th><th>Location</th></tr></thead><tbody><tr><td><code>FunctionTool</code> (agent-tools)</td><td><code>listTemplateCategoriesTool</code>, <code>listTemplatesTool</code>, <code>getTemplateDetailTool</code></td><td><code>src/assign-task/relay-assign-task.ts</code></td></tr><tr><td><code>RelayMcpTool</code> (agent-tool-mcp)</td><td><code>createAssignTaskRelayTool</code> result</td><td><code>src/assign-task/relay-assign-task.ts</code></td></tr><tr><td><code>IEventService</code> (agents)</td><td><code>createAssignTaskRelayTool</code> parameter</td><td><code>src/assign-task/relay-assign-task.ts</code></td></tr><tr><td><code>IAIProvider</code> (agents)</td><td><code>createAssignTaskRelayTool</code> parameter</td><td><code>src/assign-task/relay-assign-task.ts</code></td></tr><tr><td><code>bindWithOwnerPath</code> (agent-event-service)</td><td>relay tool owner-path propagation</td><td><code>src/assign-task/relay-assign-task.ts</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><h3 id="current-state" tabindex="-1">Current State <a class="header-anchor" href="#current-state" aria-label="Permalink to &quot;Current State&quot;">​</a></h3><ul><li><strong>1 test file exists</strong>: <code>src/assign-task/relay-assign-task.test.ts</code> (182 lines) covering relay tool execution, parameter validation, and error paths.</li><li>An offline verification scenario exists at <code>examples/verify-offline.ts</code> that exercises <code>listTemplateCategoriesTool</code>, <code>listTemplatesTool</code>, and <code>getTemplateDetailTool</code> without network calls.</li><li>Scenario record artifact: <code>examples/scenarios/offline-verify.record.json</code>.</li></ul><h3 id="gaps" tabindex="-1">Gaps <a class="header-anchor" href="#gaps" aria-label="Permalink to &quot;Gaps&quot;">​</a></h3><ul><li>No unit tests for <code>listTemplateCategoriesTool</code>, <code>listTemplatesTool</code>, or <code>getTemplateDetailTool</code>.</li><li>No integration tests verifying event service interaction during relay execution.</li></ul>`,36)]))}const g=t(d,[["render",s]]);export{m as __pageData,g as default};
